template.script:
    (function() {
      'use strict';

      /* ── state ──────────────────────────────────────────────────── */
      let _year  = ;
      let _month = ;
      let _rows  = [];          // last fetched rows
      let _selected = new Set(); // checked employee ids

      /* ── helpers ─────────────────────────────────────────────────── */
      const fmt  = (n) => Number(n).toLocaleString('en-SA', {minimumFractionDigits:0, maximumFractionDigits:0});
      const fmtD = (n) => Number(n).toFixed(1);

      function hhmm(hours) {
        const h = Math.floor(Math.abs(hours));
        const m = Math.round((Math.abs(hours) - h) * 60);
        const sign = hours < -0.01 ? '-' : '';
        return `${sign}${String(h).padStart(2,'0')}:${String(m).padStart(2,'0')}`;
      }

      function getCsrfToken() {
        const m = document.cookie.match(/(?:^|;\s*)csrf_token=([^;]+)/);
        return m ? decodeURIComponent(m[1]) : '';
      }

      async function jsonRpc(url, params) {
        const resp = await fetch(url, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'X-CSRFToken': getCsrfToken()
          },
          body: JSON.stringify({ jsonrpc:'2.0', method:'call', id:1, params: params })
        });
        const data = await resp.json();
        if (data.error) throw new Error(data.error.data?.message || data.error.message);
        return data.result;
      }

      /* ── period change ───────────────────────────────────────────── */
      window.IPR = window.IPR || {};

      IPR.changePeriod = function(val) {
        const [y, m] = val.split('-');
        window.location.href = `/odoo/instant-payroll?year=${y}&month=${m}`;
      };

      /* ── load report data ─────────────────────────────────────────── */
      IPR.loadData = async function() {
        const overlay = document.getElementById('loadingOverlay');
        overlay.classList.add('active');

        const deptId = document.getElementById('deptFilter').value || null;

        try {
          const result = await jsonRpc('/odoo/instant-payroll/data', {
            year: _year, month: _month,
            department_id: deptId ? parseInt(deptId) : null
          });

          _rows = result.rows;
          _selected.clear();
          renderTable(_rows);
          renderSummary(result.rows.length, result.grand_totals);

        } catch(e) {
          document.getElementById('reportBody').innerHTML =
            `<tr><td colspan="16" class="text-center text-danger py-4">
              <i class="fa fa-exclamation-triangle me-2"></i>${e.message}
             </td></tr>`;
        } finally {
          overlay.classList.remove('active');
        }
      };

      /* ── render table rows ─────────────────────────────────────────── */
      function renderTable(rows) {
        const tbody = document.getElementById('reportBody');
        if (!rows.length) {
          tbody.innerHTML = '<tr><td colspan="16" class="text-center text-muted py-5">No employees found.</td></tr>';
          return;
        }

        tbody.innerHTML = rows.map(r => {
          const diffClass = r.diff > 0.01 ? 'col-diff-pos' : r.diff < -0.01 ? 'col-diff-neg' : 'text-muted';
          const diffSign  = r.diff > 0.01 ? '+' : '';
          const netClass  = r.net < 0 ? 'text-danger' : '';

          return `
<tr class="ipr-row" data-id="${r.id}">
  <!-- Employee -->
  <td class="ipr-sticky-col ps-3">
    <div class="d-flex align-items-center gap-2">
      <input type="checkbox" class="form-check-input emp-chk no-print"
             value="${r.id}" onchange="IPR.onCheckbox(this)"/>
      <div>
        ${r.is_on_leave_now ? '<span class="badge ipr-badge-blue" style="font-size:.55rem">On Leave</span><br/>' : ''}
        <span class="fw-bold">${r.name}</span>
        <br/><small class="text-muted">${r.job}</small>
      </div>
    </div>
  </td>
  <!-- Dept -->
  <td class="text-center text-muted no-print" style="font-size:.65rem">${r.department}</td>
  <!-- Hours -->
  <td class="text-end font-monospace fw-bold">${hhmm(r.worked_hours)}</td>
  <!-- Diff -->
  <td class="text-end font-monospace fw-bold ${diffClass}">${diffSign}${hhmm(r.diff)}</td>
  <!-- Shifts -->
  <td class="text-center text-muted no-print">${r.shift_count}</td>
  <!-- Days worked -->
  <td class="text-center text-muted no-print">${r.days_worked}/${r.expected_working_days}</td>
  <!-- Gross -->
  <td class="text-end font-monospace fw-bold text-primary">${fmt(r.gross)}</td>
  <!-- Day deduction -->
  <td class="text-end font-monospace text-danger">${r.absent_deduction > 0.01 ? '-'+fmt(r.absent_deduction) : '—'}</td>
  <!-- Hourly deduction -->
  <td class="text-end font-monospace text-danger">${r.hourly_deduction > 0.01 ? '-'+fmt(r.hourly_deduction) : '—'}</td>
  <!-- Total deduction -->
  <td class="text-end font-monospace fw-bold text-danger">${r.deduction > 0.01 ? fmt(r.deduction) : '—'}</td>
  <!-- OT -->
  <td class="text-end font-monospace fw-bold text-success">${r.overtime > 0.01 ? '+'+fmt(r.overtime) : '—'}</td>
  <!-- Absent days (auto + manual adj) -->
  <td class="text-center">
    <span class="text-danger fw-bold" style="font-size:.7rem">${fmtD(r.absent_days_from_leave)}</span>
    <br/>
    <input type="number" step="0.5" class="ipr-input red no-print"
           placeholder="Adj" value="${r.adj_absent_days || ''}"
           onchange="IPR.saveAdj(${r.id}, 'absent_days_adjustment', this.value)"
           title="Additional absent days to add"/>
  </td>
  <!-- Other deductions -->
  <td class="text-center no-print">
    <input type="number" step="1" class="ipr-input red"
           placeholder="0" value="${r.adj_other_ded || ''}"
           onchange="IPR.saveAdj(${r.id}, 'other_deductions', this.value)"
           title="Extra deductions (advances, etc.)"/>
  </td>
  <!-- Reimbursements -->
  <td class="text-center no-print">
    <input type="number" step="1" class="ipr-input green"
           placeholder="0" value="${r.reimb || ''}"
           onchange="IPR.saveAdj(${r.id}, 'reimbursements', this.value)"
           title="Reimbursements / expense claims"/>
  </td>
  <!-- Net -->
  <td class="text-end col-net pe-3 ${netClass}">
    <span class="badge ${r.net < 0 ? 'bg-danger' : 'bg-dark'} fs-6">
      ${fmt(r.net)}
    </span>
  </td>
  <!-- Leave balance -->
  <td class="text-center no-print">
    <span class="badge ${r.leave_balance > 0 ? 'ipr-badge-green' : 'ipr-badge-red'}"
          title="Allocated: ${r.leave_allocation_total} | Taken: ${r.leave_taken_ytd}">
      ${fmtD(r.leave_balance)} d
    </span>
  </td>
</tr>
          `;
        }).join('');
      }

      /* ── render summary cards ─────────────────────────────────────── */
      function renderSummary(count, g) {
        document.getElementById('sumEmployees').textContent = count;
        document.getElementById('sumGross').textContent     = fmt(g.gross);
        document.getElementById('sumDed').textContent       = fmt(g.deduction);
        document.getElementById('sumOT').textContent        = '+' + fmt(g.overtime);
        document.getElementById('sumHours').textContent     = hhmm(g.worked_hours);
        document.getElementById('sumNet').textContent       = fmt(g.net);
        document.getElementById('summaryCards').style.removeProperty('display');

        // Footer
        document.getElementById('ftHours').textContent   = hhmm(g.worked_hours);
        document.getElementById('ftGross').textContent   = fmt(g.gross);
        document.getElementById('ftDed').textContent     = fmt(g.deduction);
        document.getElementById('ftOT').textContent      = '+' + fmt(g.overtime);
        document.getElementById('ftNet').textContent     = fmt(g.net);
        document.getElementById('ftOtherDed').textContent = fmt(g.other_ded);
        document.getElementById('ftReimb').textContent   = fmt(g.reimb);
        document.getElementById('reportFoot').style.display = '';
      }

      /* ── save adjustment (debounced) ──────────────────────────────── */
      const _adjBuffers = {};
      const _adjTimers  = {};

      IPR.saveAdj = function(empId, field, rawVal) {
        const val = parseFloat(rawVal) || 0;
        if (!_adjBuffers[empId]) _adjBuffers[empId] = {};
        _adjBuffers[empId][field] = val;

        clearTimeout(_adjTimers[empId]);
        _adjTimers[empId] = setTimeout(async () => {
          const buf = _adjBuffers[empId];
          // Merge with current row values so we don't reset other fields
          const row = _rows.find(r => r.id === empId) || {};
          const params = {
            employee_id: empId,
            year: _year,
            month: _month,
            other_deductions:       buf.other_deductions      ?? row.adj_other_ded  ?? 0,
            reimbursements:         buf.reimbursements        ?? row.reimb           ?? 0,
            absent_days_adjustment: buf.absent_days_adjustment ?? row.adj_absent_days ?? 0,
          };
          try {
            await jsonRpc('/odoo/instant-payroll/save-adjustment', params);
            // Reload to refresh computed values
            IPR.loadData();
          } catch(e) {
            console.error('Failed to save adjustment', e);
          }
        }, 800);
      };

      /* ── export CSV ───────────────────────────────────────────────── */
      IPR.exportCsv = function() {
        if (!_rows.length) return;
        const headers = ['Employee','Department','Worked Hours','Diff (h)','Gross (SAR)',
                         'Day Deduction','Hour Deduction','Total Deduction','Overtime',
                         'Absent Days','Other Ded.','Reimb.','Net (SAR)','Leave Balance (d)'];
        const rows = _rows.map(r => [
          r.name, r.department,
          hhmm(r.worked_hours), r.diff.toFixed(2),
          r.gross, r.absent_deduction, r.hourly_deduction,
          r.deduction, r.overtime,
          r.total_absent_days, r.adj_other_ded, r.reimb,
          r.net, r.leave_balance
        ]);
        const csv = [headers, ...rows].map(row =>
          row.map(v => `"${String(v).replace(/"/g,'""')}"`).join(',')
        ).join('\n');
        const blob = new Blob([csv], {type:'text/csv;charset=utf-8;'});
        const link = document.createElement('a');
        link.href = URL.createObjectURL(blob);
        link.download = `Payroll_${_year}_${String(_month).padStart(2,'0')}.csv`;
        link.click();
      };

      /* ── checkbox / select-all ─────────────────────────────────────── */
      IPR.onCheckbox = function(el) {
        const id = parseInt(el.value);
        if (el.checked) _selected.add(id);
        else _selected.delete(id);
        document.getElementById('btnCreateBatch').style.display =
          _selected.size > 0 ? 'inline-flex' : 'none';
      };

      IPR.toggleSelectAll = function(el) {
        document.querySelectorAll('.emp-chk').forEach(chk => {
          chk.checked = el.checked;
          IPR.onCheckbox(chk);
        });
      };

      /* ── push to payroll batch ─────────────────────────────────────── */
      IPR.createPayrollBatch = async function() {
        if (!_selected.size) return;
        if (!confirm(`Create a payroll batch for ${_selected.size} selected employee(s)?`)) return;

        try {
          const result = await jsonRpc('/odoo/instant-payroll/create-payroll-batch', {
            year: _year,
            month: _month,
            employee_ids: Array.from(_selected)
          });

          if (result.status === 'ok') {
            alert(`✅ Payroll batch created with ${result.slips_created} payslip(s).\n\nOpening batch now…`);
            window.location.href = result.batch_url;
          } else {
            alert('⚠️ ' + result.message);
          }
        } catch(e) {
          alert('Error: ' + e.message);
        }
      };

      /* ── auto-load on page ready ──────────────────────────────────── */
      document.addEventListener('DOMContentLoaded', function() {
        IPR.loadData();
      });

    })();
